17	// routeStatusJSON is the top-level JSON output shape.
18	type routeStatusJSON struct {
19		Routes          []routeStatusRouteJSON    `json:"routes,omitempty"`
20		RecentDecisions []routeStatusDecisionJSON `json:"recent_decisions,omitempty"`
21		ActiveCooldowns []routeStatusCooldownJSON `json:"active_cooldowns,omitempty"`
22	}
