24	// routeStatusCandidateJSON is the JSON-serialisable form of one route candidate.
25	type routeStatusCandidateJSON struct {
26		Provider      string  `json:"provider"`
27		Model         string  `json:"model,omitempty"`
28		Healthy       bool    `json:"healthy"`
29		InCooldown    bool    `json:"in_cooldown,omitempty"`
