37	// routeStatusRouteJSON is the JSON-serialisable form of one model route.
38	type routeStatusRouteJSON struct {
39		RouteKey         string                     `json:"route_key"`
40		Strategy         string                     `json:"strategy"`
41		SelectedProvider string                     `json:"selected_provider,omitempty"`
42		SelectedModel    string                     `json:"selected_model,omitempty"`
43		Candidates       []routeStatusCandidateJSON `json:"candidates"`
44	}
