150	// routeStatusDecisionJSON is the JSON-serialisable form of one routing decision
151	// from either the RoutingMetricsStore ("metrics-store") or kind:routing bead
152	// evidence ("bead-evidence").
153	type routeStatusDecisionJSON struct {
154		ObservedAt      string `json:"observed_at"`
155		Source          string `json:"source"`                     // "bead-evidence" or "metrics-store"
156		BeadID          string `json:"bead_id,omitempty"`          // bead-evidence only
157		Harness         string `json:"harness,omitempty"`          // metrics-store only
158		CanonicalTarget string `json:"canonical_target,omitempty"` // metrics-store only
159		Provider        string `json:"provider,omitempty"`         // bead-evidence only
160		Model           string `json:"model,omitempty"`
161		RouteReason     string `json:"route_reason,omitempty"` // bead-evidence only
