183	func (f *CommandFactory) newAgentRouteStatusCommand() *cobra.Command {
184		cmd := &cobra.Command{
185			Use:   "route-status",
186			Short: "Show routing table, recent decisions, and active health cooldowns",
187			Long: `Shows the current provider routing state, recent routing decisions, and
188	any health cooldowns currently in effect.
189	
190	Uses the ddx-agent Service.RouteStatus API. Requires model routes to be
191	configured in .agent/config.yaml.
192	
193	Examples:
194	  ddx agent route-status
195	  ddx agent route-status --model qwen3.5-27b
196	  ddx agent route-status --json`,
197			Args: cobra.NoArgs,
198			RunE: func(cmd *cobra.Command, args []string) error {
199				model, _ := cmd.Flags().GetString("model")
200				asJSON, _ := cmd.Flags().GetBool("json")
201	
202				svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
203				if err != nil {
204					return fmt.Errorf("loading agent config: %w", err)
205				}
206	
207				ctx := context.Background()
208				report, err := svc.RouteStatus(ctx)
209				if err != nil {
210					return fmt.Errorf("getting route status: %w", err)
211				}
212	
213				// Filter by --model flag if specified.
214				if model != "" {
215					found := false
216					for _, r := range report.Routes {
217						if r.Model == model {
218							found = true
219							break
220						}
221					}
222					if !found {
223						return fmt.Errorf("no route configured for model key %q — check .agent/config.yaml", model)
224					}
225					filtered := report.Routes[:0]
226					for _, r := range report.Routes {
227						if r.Model == model {
228							filtered = append(filtered, r)
229						}
230					}
231					report.Routes = filtered
232				}
233	
234				if len(report.Routes) == 0 {
235					if !asJSON {
236						fmt.Fprintln(cmd.OutOrStdout(), "No model routes configured in .agent/config.yaml.")
237						fmt.Fprintln(cmd.OutOrStdout(), "Use --model <route-key> or configure model_routes in .agent/config.yaml.")
238					} else {
239						enc := json.NewEncoder(cmd.OutOrStdout())
240						enc.SetIndent("", "  ")
241						return enc.Encode(routeStatusJSON{})
242					}
243					return nil
244				}
245	
246				// Load recent routing decisions from two complementary sources:
247				//
248				//  1. RoutingMetricsStore — harness-level analytics (latency, success
249				//     rate) for every agent run, stored in routing-outcomes.jsonl.
250				//  2. kind:routing bead events — execution provenance per bead (which
251				//     provider/model was selected and why), tied to a specific bead ID.
252				var recentDecisions []recentRoutingDecision
253	
254				if logDir := agent.SessionLogDirForWorkDir(f.WorkingDir); logDir != "" {
255					store := agent.NewRoutingMetricsStore(logDir)
256					outcomes, _ := store.ReadOutcomes()
257					for _, o := range outcomes {
258						recentDecisions = append(recentDecisions, recentRoutingDecision{
259							ObservedAt:   o.ObservedAt,
260							Source:       "metrics-store",
261							Harness:      o.Harness,
262							Provider:     o.CanonicalTarget,
263							Model:        o.Model,
264							Success:      o.Success,
265							SuccessKnown: true,
266							LatencyMS:    o.LatencyMS,
267						})
268					}
269				}
270	
271				// Merge kind:routing bead evidence entries.
272				recentDecisions = append(recentDecisions, beadRoutingDecisionsFromStore(f.WorkingDir)...)
273	
