295							ck := entry.Model + "|" + cand.Provider
296							if _, seen := seenCooldownKeys[ck]; !seen {
297								seenCooldownKeys[ck] = struct{}{}
298								// FailedAt is not directly available; use Until minus a best-effort estimate.
299								// We record Until and leave FailedAt as zero for cooldowns from the service.
300								activeCooldowns = append(activeCooldowns, cooldownEntry{
301									route:         entry.Model,
302									provider:      cand.Provider,
303									cooldownUntil: cand.Cooldown.Until,
304								})
305							}
306						}
307					}
308				}
309				sort.Slice(activeCooldowns, func(i, j int) bool {
310					return activeCooldowns[i].route < activeCooldowns[j].route
