72	func appendJSONLRecord(path string, v any) error {
73		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
74			return err
75		}
76		data, err := json.Marshal(v)
77		if err != nil {
78			return err
79		}
80		f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
81		if err != nil {
82			return err
83		}
84		defer f.Close()
85		if _, err := f.Write(append(data, '\n')); err != nil {
86			return err
87		}
88		return nil
89	}
