91	// BuildBurnSummaries derives a relative subscription-pressure score from quota snapshots.
92	func BuildBurnSummaries(snapshots []QuotaSnapshot) []BurnSummary {
93		type groupKey struct {
94			harness string
95			surface string
96			target  string
97		}
98	
99		grouped := make(map[groupKey][]QuotaSnapshot)
100		for _, snapshot := range snapshots {
101			key := groupKey{
102				harness: snapshot.Harness,
103				surface: snapshot.Surface,
104				target:  snapshot.CanonicalTarget,
105			}
106			grouped[key] = append(grouped[key], snapshot)
107		}
108	
109		keys := make([]groupKey, 0, len(grouped))
110		for key := range grouped {
111			keys = append(keys, key)
112		}
113		sort.Slice(keys, func(i, j int) bool {
114			if keys[i].harness != keys[j].harness {
115				return keys[i].harness < keys[j].harness
116			}
117			if keys[i].surface != keys[j].surface {
118				return keys[i].surface < keys[j].surface
119			}
120			return keys[i].target < keys[j].target
121		})
122	
123		summaries := make([]BurnSummary, 0, len(keys))
124		for _, key := range keys {
125			group := grouped[key]
126			sort.Slice(group, func(i, j int) bool {
127				return group[i].ObservedAt.Before(group[j].ObservedAt)
128			})
129	
130			first := group[0]
131			last := group[len(group)-1]
132			burnIndex := 0.0
133			if last.UsedPercent > 0 {
134				burnIndex = float64(last.UsedPercent) / 100.0
135			}
136	
137			trend := "flat"
138			if len(group) > 1 {
139				delta := last.UsedPercent - first.UsedPercent
140				switch {
141				case delta > 0:
142					trend = "rising"
143				case delta < 0:
144					trend = "falling"
145				}
146			}
147	
148			confidence := 0.4
149			if len(group) > 1 {
150				confidence = 0.6
151			}
152			if len(group) > 3 {
153				confidence = 0.8
154			}
155			if len(group) > 6 {
156				confidence = 1.0
157			}
158	
159			basis := fmt.Sprintf("%d snapshot(s)", len(group))
160			if first.ObservedAt != (time.Time{}) && last.ObservedAt != (time.Time{}) {
161				basis = fmt.Sprintf("%s from %s to %s",
162					basis,
163					first.ObservedAt.UTC().Format(time.RFC3339),
164					last.ObservedAt.UTC().Format(time.RFC3339),
165				)
166			}
167	
168			summaries = append(summaries, BurnSummary{
169				Harness:         key.harness,
170				Surface:         key.surface,
171				CanonicalTarget: key.target,
172				ObservedAt:      last.ObservedAt,
173				BurnIndex:       burnIndex,
174				Trend:           trend,
175				Confidence:      confidence,
176				Basis:           basis,
177			})
178		}
179	
180		return summaries
181	}
