222	// ShouldEscalate reports whether status warrants escalating to the next tier.
223	// Structural failures (e.g. validation errors) do not escalate because a
224	// smarter model cannot fix a malformed prompt or corrupted bead state.
225	func ShouldEscalate(status string) bool {
226		return EscalatableStatuses[status]
227	}
