229	// FormatTierAttemptBody formats the body of a tier-attempt bead event.
230	func FormatTierAttemptBody(tier, harness, model, probeResult, detail string) string {
231		body := fmt.Sprintf("tier=%s harness=%s model=%s", tier, harness, model)
232		if probeResult != "" {
233			body += " probe=" + probeResult
234		}
235		if detail != "" {
236			body += "\n" + detail
237		}
238		return body
239	}
240	
241	// EscalationWinningExhausted is the sentinel value written into the
242	// winning_tier field of an escalation-summary body when the escalation loop
243	// ran through every eligible tier without producing a successful attempt.
244	const EscalationWinningExhausted = "exhausted"
245	
246	// TierAttemptRecord is one row of an escalation trace. It captures the
247	// tier/harness/model that was tried, the status that attempt returned, and
248	// the cost/duration the harness reported for that attempt. Skipped tiers
249	// (no viable provider) are recorded with zero cost and zero duration.
250	type TierAttemptRecord struct {
251		Tier       string  `json:"tier"`
252		Harness    string  `json:"harness,omitempty"`
253		Model      string  `json:"model,omitempty"`
254		Status     string  `json:"status"`
255		CostUSD    float64 `json:"cost_usd"`
256		DurationMS int64   `json:"duration_ms"`
257	}
258	
259	// EscalationSummary is the structured body of a kind:escalation-summary bead
260	// event. It captures the entire escalation trace so an operator can diagnose
261	// which tiers were tried, which one won (if any), and how much the path cost.
262	type EscalationSummary struct {
263		TiersAttempted []TierAttemptRecord `json:"tiers_attempted"`
264		WinningTier    string              `json:"winning_tier"`
265		TotalCostUSD   float64             `json:"total_cost_usd"`
266		WastedCostUSD  float64             `json:"wasted_cost_usd"`
267	}
268	
269	// BuildEscalationSummary computes the summary body from the ordered list of
270	// attempts. winningTier is the string of the tier whose attempt succeeded;
271	// pass "" when the escalation was exhausted, in which case winning_tier is
272	// set to EscalationWinningExhausted. Total cost is the sum of all attempt
273	// costs; wasted cost is the sum of attempts whose status is not
274	// SuccessStatus.
275	func BuildEscalationSummary(attempts []TierAttemptRecord, winningTier string) EscalationSummary {
276		out := EscalationSummary{
277			TiersAttempted: append([]TierAttemptRecord{}, attempts...),
278			WinningTier:    winningTier,
279		}
280		if out.WinningTier == "" {
281			out.WinningTier = EscalationWinningExhausted
282		}
283		for _, a := range attempts {
284			out.TotalCostUSD += a.CostUSD
285			if a.Status != SuccessStatus {
286				out.WastedCostUSD += a.CostUSD
287			}
288		}
289		return out
290	}
291	
292	// BeadEventAppender records append-only evidence events on a bead. Mirrors
293	// agent.BeadEventAppender so escalation can append events without importing
294	// agent. *bead.Store satisfies both interfaces.
295	type BeadEventAppender interface {
296		AppendEvent(id string, event bead.BeadEvent) error
297	}
298	
299	// AppendEscalationSummaryEvent writes a kind:escalation-summary event to the
300	// bead with a JSON body describing the tier escalation trace. It is a
301	// best-effort operation — errors from the underlying store are returned so
302	// callers can log them, but callers typically ignore the error so telemetry
303	// failures never abort the main execute-bead flow.
304	func AppendEscalationSummaryEvent(appender BeadEventAppender, beadID, actor string, attempts []TierAttemptRecord, winningTier string, createdAt time.Time) error {
305		if appender == nil || beadID == "" {
306			return nil
307		}
308		summary := BuildEscalationSummary(attempts, winningTier)
309		body, err := json.Marshal(summary)
310		if err != nil {
311			return err
312		}
313		return appender.AppendEvent(beadID, bead.BeadEvent{
314			Kind:      "escalation-summary",
315			Summary:   fmt.Sprintf("winning_tier=%s attempts=%d total_cost_usd=%.4f wasted_cost_usd=%.4f", summary.WinningTier, len(attempts), summary.TotalCostUSD, summary.WastedCostUSD),
316			Body:      string(body),
317			Actor:     actor,
318			Source:    "ddx agent execute-loop",
319			CreatedAt: createdAt,
320		})
321	}
