686	func (f *CommandFactory) newAgentDoctorCommand() *cobra.Command {
687		cmd := &cobra.Command{
688			Use:          "doctor",
689			Short:        "Check agent harness health",
690			Args:         cobra.NoArgs,
691			SilenceUsage: true,
692			RunE: func(cmd *cobra.Command, args []string) error {
693				checkConnectivity, _ := cmd.Flags().GetBool("connectivity")
694				checkRouting, _ := cmd.Flags().GetBool("routing")
695				timeoutStr, _ := cmd.Flags().GetString("timeout")
696				asJSON, _ := cmd.Flags().GetBool("json")
697	
698				// Parse timeout (default 15s for connectivity checks)
699				probeTimeout := 15 * time.Second
700				if timeoutStr != "" {
701					if t, err := time.ParseDuration(timeoutStr); err == nil {
702						probeTimeout = t
703					}
704				}
705	
706				// Routing mode: derive full routing state per harness via service.
707				if checkRouting {
708					svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
709					if svcErr != nil {
710						return fmt.Errorf("agent doctor: failed to initialize service: %w", svcErr)
711					}
712					ctx := cmd.Context()
713					harnesses, listErr := svc.ListHarnesses(ctx)
714					if listErr != nil {
715						return fmt.Errorf("agent doctor: listing harnesses: %w", listErr)
716					}
717	
718					// Refresh quota caches via HealthCheck, then re-fetch harness list.
719					for _, h := range harnesses {
720						_ = svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: h.Name})
721					}
722					harnesses, listErr = svc.ListHarnesses(ctx)
723					if listErr != nil {
724						return fmt.Errorf("agent doctor: re-listing harnesses after health check: %w", listErr)
725					}
726	
727					type routingState struct {
728						Installed     bool                         `json:"installed"`
729						Reachable     bool                         `json:"reachable"`
730						Authenticated bool                         `json:"authenticated"`
731						QuotaOK       bool                         `json:"quota_ok"`
732						QuotaState    string                       `json:"quota_state,omitempty"`
733						Degraded      bool                         `json:"degraded"`
734						Error         string                       `json:"error,omitempty"`
735						Quota         *agent.QuotaInfo             `json:"quota,omitempty"`
736						RoutingSignal *agent.RoutingSignalSnapshot `json:"routing_signal,omitempty"`
737						LastChecked   time.Time                    `json:"last_checked,omitempty"`
738					}
739					type routingEntry struct {
740						Name  string       `json:"name"`
741						State routingState `json:"state"`
742					}
743					now := time.Now()
744					var entries []routingEntry
745					for _, hi := range harnesses {
746						st := routingState{
747							Installed:   hi.Available,
748							LastChecked: now,
749						}
750						// Derive reachable/authenticated: HealthCheck already ran; available == reachable for harnesses.
751						st.Reachable = hi.Available
752						st.Authenticated = hi.Available
753						st.QuotaOK = true
754						// Derive quota state from upstream HarnessInfo.Quota.
755						if hi.Quota != nil {
756							switch hi.Quota.Status {
757							case "ok":
758								st.QuotaState = "ok"
759							case "stale":
760								st.QuotaState = "ok"
761							}
762							if len(hi.Quota.Windows) > 0 {
763								// Report worst window as current quota for routing.
764								var worstPct int
765								var worstReset string
766								blocked := false
767								for _, w := range hi.Quota.Windows {
768									if w.LimitID == "extra" {
769										continue
770									}
771									if w.State == "blocked" {
772										blocked = true
773										worstReset = w.ResetsAt
774									}
775									if int(w.UsedPercent+0.5) > worstPct {
776										worstPct = int(w.UsedPercent + 0.5)
777									}
778								}
779								if blocked {
780									st.QuotaState = "blocked"
781									st.QuotaOK = false
782								}
783								if worstPct > 0 && st.Quota == nil {
784									st.Quota = &agent.QuotaInfo{
785										PercentUsed: worstPct,
786										ResetDate:   worstReset,
787									}
788								}
789							}
790							// Translate upstream HarnessInfo into the local
791							// RoutingSignalSnapshot shape so the --json consumers
792							// (and human text below) keep their existing shape.
793							signal := harnessInfoToRoutingSignal(hi, now)
794							if signal.Provider != "" {
795								st.RoutingSignal = &signal
796							}
797						}
798						if st.QuotaState == "" {
799							st.QuotaState = "unknown"
800						}
801						if hi.Error != "" {
802							st.Error = hi.Error
803						}
804						entries = append(entries, routingEntry{Name: hi.Name, State: st})
805					}
806					if asJSON {
807						enc := json.NewEncoder(cmd.OutOrStdout())
808						enc.SetIndent("", "  ")
809						return enc.Encode(entries)
810					}
811					for _, e := range entries {
812						st := e.State
813						indicator := "ok"
814						if !st.Installed {
815							indicator = "not installed"
816						} else if !st.Reachable {
817							indicator = "not reachable"
818						} else if !st.Authenticated {
819							indicator = "not authenticated"
820						} else if st.QuotaState == "blocked" || (!st.QuotaOK && st.QuotaState != "unknown") {
821							indicator = "quota exceeded"
822						} else if st.Degraded {
823							indicator = "degraded"
824						} else if st.QuotaState == "unknown" {
825							indicator = "quota unknown"
826						}
827						quotaState := st.QuotaState
828						if quotaState == "" {
829							if st.QuotaOK {
830								quotaState = "ok"
831							} else {
832								quotaState = "blocked"
833							}
834						}
835						line := fmt.Sprintf("%-12s  installed=%-5v  reachable=%-5v  auth=%-5v  quota=%-8s  [%s]",
836							e.Name, st.Installed, st.Reachable, st.Authenticated, quotaState, indicator)
837						if st.Quota != nil {
838							quota := st.Quota
839							if quota.ResetDate != "" {
840								line += fmt.Sprintf("  quota: %d%% of %s (resets %s)", quota.PercentUsed, quota.LimitWindow, quota.ResetDate)
841							} else {
842								line += fmt.Sprintf("  quota: %d%% of %s", quota.PercentUsed, quota.LimitWindow)
843							}
844						}
845						if st.RoutingSignal != nil {
846							signal := st.RoutingSignal
847							line += fmt.Sprintf("  source: %s/%s", signal.Source.Provider, signal.Source.Kind)
848							if signal.Source.Freshness != "" {
849								line += fmt.Sprintf("  freshness: %s", signal.Source.Freshness)
850							}
851							if signal.HistoricalUsage.TotalTokens > 0 {
852								line += fmt.Sprintf("  native-usage: %d tokens", signal.HistoricalUsage.TotalTokens)
