// AdaptiveMinTier inspects the most recent `window` entries under
// workingDir/.ddx/executions/*/result.json, computes the cheap-tier trailing
// success rate, and returns a recommendation:
//
//   - When cheap-tier success rate < AdaptiveMinTierThreshold (and at least
//     AdaptiveMinTierMinSamples cheap attempts were observed), returns
//     TierStandard with Skipped=true.
//   - Otherwise returns TierCheap with Skipped=false.
//
// A tier is identified by resolving (harness, model) back through the
// supplied resolver — attempts whose harness/model do not match any known
// tier mapping are ignored. Infrastructure failures (failure_mode in
// AdaptiveMinTierInfraFailureModes) are excluded from the success-rate
// calculation. Executions before a reset marker are ignored. When
// workingDir has no executions directory (fresh project) the cheap tier
// is kept in-range so a first run is not artificially restricted.
func AdaptiveMinTier(workingDir string, window int, resolver TierResolver) AdaptiveMinTierResult {
	diag := computeAdaptiveDiagnostics(workingDir, window, resolver)
	return AdaptiveMinTierResult{
		Tier:             diag.EffectiveFloor,
		CheapAttempts:    diag.CheapAttempts,
		CheapSuccessRate: diag.CheapSuccessRate,
		Skipped:          diag.IsSkippingCheap,
	}
}

// ComputeAdaptiveMinTierDiagnostics returns the full diagnostic state for the
// adaptive min-tier computation. Callers use this to power the
// 'ddx agent route-status --adaptive' display without re-implementing the
// traversal logic.
func ComputeAdaptiveMinTierDiagnostics(workingDir string, window int, resolver TierResolver) AdaptiveMinTierDiagnostics {
	return computeAdaptiveDiagnostics(workingDir, window, resolver)
}

// parseDirTimestamp parses the timestamp prefix from an execution directory
// name (format YYYYMMDDTHHMMSS-<hex>) into a UTC time. Returns false when
// the name does not match the expected format.
func parseDirTimestamp(name string) (time.Time, bool) {
	if len(name) < 15 {
		return time.Time{}, false
	}
	t, err := time.Parse("20060102T150405", name[:15])
	if err != nil {
		return time.Time{}, false
	}
	return t.UTC(), true
}

func computeAdaptiveDiagnostics(workingDir string, window int, resolver TierResolver) AdaptiveMinTierDiagnostics {
	diag := AdaptiveMinTierDiagnostics{
		WindowSize:     window,
		Threshold:      AdaptiveMinTierThreshold,
		MinSamples:     AdaptiveMinTierMinSamples,
		EffectiveFloor: TierCheap,
	}

	if m := ReadAdaptiveResetMarker(workingDir); m != nil {
		diag.ResetAt = m.ResetAt
	}

	execRoot := filepath.Join(workingDir, ".ddx", "executions")
	entries, err := os.ReadDir(execRoot)
	if err != nil {
		return diag
	}

	names := make([]string, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() {
			names = append(names, entry.Name())
		}
	}
	// Directory names are sortable timestamps (YYYYMMDDTHHMMSS-<hash>), so
	// lexicographic sort is chronological.
	sort.Strings(names)

	type attempt struct {
		tier    ModelTier
		success bool
		infra   bool // excluded from success rate: infra/config failure
	}
	collected := make([]attempt, 0, len(names))
	for _, name := range names {
		// Skip executions that predate the reset marker.
		if !diag.ResetAt.IsZero() {
			if ts, ok := parseDirTimestamp(name); ok && ts.Before(diag.ResetAt) {
				continue
			}
		}

		resultPath := filepath.Join(execRoot, name, "result.json")
		raw, err := os.ReadFile(resultPath)
		if err != nil {
			continue
		}
		var res taskResultLite
		if err := json.Unmarshal(raw, &res); err != nil {
			continue
		}
		if res.Harness == "" {
			continue
		}
		tier := classifyAttemptTier(res.Harness, res.Model, resolver)
		if tier == "" {
			continue
		}
		collected = append(collected, attempt{
			tier:    tier,
			success: res.Outcome == "task_succeeded",
			infra:   AdaptiveMinTierInfraFailureModes[res.FailureMode],
		})
	}
	if window > 0 && len(collected) > window {
		collected = collected[len(collected)-window:]
	}

	diag.TotalInWindow = len(collected)
	var cheapAttempts, cheapSuccesses, cheapInfraSkipped int
	for _, a := range collected {
		if a.tier != TierCheap {
			continue
		}
		if a.infra {
			cheapInfraSkipped++
			continue
		}
		cheapAttempts++
		if a.success {
			cheapSuccesses++
		}
	}
	diag.CheapAttempts = cheapAttempts
	diag.CheapSuccesses = cheapSuccesses
	diag.CheapInfraSkipped = cheapInfraSkipped

	if cheapAttempts > 0 {
		diag.CheapSuccessRate = float64(cheapSuccesses) / float64(cheapAttempts)
	}
	if cheapAttempts >= AdaptiveMinTierMinSamples && diag.CheapSuccessRate < AdaptiveMinTierThreshold {
		diag.EffectiveFloor = TierStandard
		diag.IsSkippingCheap = true
	}
	return diag
}

// adaptiveStateJSON is the JSON shape for --adaptive output appended to
// routeStatusJSON when --adaptive is set.
type adaptiveStateJSON struct {
	WindowSize        int     `json:"window_size"`
	TotalInWindow     int     `json:"total_in_window"`
	CheapAttempts     int     `json:"cheap_attempts"`
	CheapSuccesses    int     `json:"cheap_successes"`
	CheapInfraSkipped int     `json:"cheap_infra_skipped"`
	CheapSuccessRate  float64 `json:"cheap_success_rate"`
	Threshold         float64 `json:"threshold"`
	MinSamples        int     `json:"min_samples"`
	EffectiveFloor    string  `json:"effective_floor"`
	IsSkippingCheap   bool    `json:"is_skipping_cheap"`
	ResetAt           string  `json:"reset_at,omitempty"`
}

func (f *CommandFactory) newAgentRouteStatusResetCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:          "reset",
		Short:        "Clear adaptive min-tier state, returning cheap-tier evaluation to a clean baseline",
		Args:         cobra.NoArgs,
		SilenceUsage: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			yes, _ := cmd.Flags().GetBool("yes")
			out := cmd.OutOrStdout()

			if !yes {
				fmt.Fprintln(out, "This will write a reset marker that causes the adaptive min-tier logic")
				fmt.Fprintln(out, "to ignore all execution history recorded before this moment.")
				fmt.Fprintln(out, "Cheap-tier eligibility will be re-evaluated on its own merits.")
				fmt.Fprintln(out)
				fmt.Fprintln(out, "Re-run with --yes to confirm:")
				fmt.Fprintln(out, "  ddx agent route-status reset --yes")
				return nil
			}

			path, err := escalation.WriteAdaptiveResetMarker(f.WorkingDir)
			if err != nil {
				return fmt.Errorf("route-status reset: %w", err)
			}
			fmt.Fprintf(out, "Adaptive min-tier state cleared.\n\n")
			fmt.Fprintf(out, "Touched: %s\n", path)
			fmt.Fprintf(out, "\nCheap-tier will now be evaluated from a clean baseline.\n")
			fmt.Fprintf(out, "Run 'ddx agent route-status --adaptive' to verify the new state.\n")
			return nil
		},
	}
	cmd.Flags().Bool("yes", false, "Confirm the reset without an interactive prompt")
	return cmd
}

func (f *CommandFactory) newAgentRouteStatusCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "route-status",
		Short: "Show routing table, recent decisions, and active health cooldowns",
		Long: `Shows the current provider routing state, recent routing decisions, and
any health cooldowns currently in effect.

Use --adaptive to display adaptive min-tier state (cheap-tier success rate,
effective floor, reset status). This works without model routes configured.

Use the 'reset' subcommand to clear the adaptive min-tier trailing window:
  ddx agent route-status reset --yes

Examples:
  ddx agent route-status
  ddx agent route-status --adaptive
  ddx agent route-status --model qwen3.5-27b
  ddx agent route-status --json`,
		Args: cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			model, _ := cmd.Flags().GetString("model")
			asJSON, _ := cmd.Flags().GetBool("json")
			showAdaptive, _ := cmd.Flags().GetBool("adaptive")
			adaptiveWindow, _ := cmd.Flags().GetInt("adaptive-window")

			// --adaptive: display adaptive min-tier state without requiring routes.
			if showAdaptive {
				diag := escalation.ComputeAdaptiveMinTierDiagnostics(f.WorkingDir, adaptiveWindow, agent.ResolveModelTier)
				if asJSON {
					aj := adaptiveStateJSON{
						WindowSize:        diag.WindowSize,
						TotalInWindow:     diag.TotalInWindow,
						CheapAttempts:     diag.CheapAttempts,
						CheapSuccesses:    diag.CheapSuccesses,
						CheapInfraSkipped: diag.CheapInfraSkipped,
						CheapSuccessRate:  diag.CheapSuccessRate,
						Threshold:         diag.Threshold,
						MinSamples:        diag.MinSamples,
						EffectiveFloor:    string(diag.EffectiveFloor),
						IsSkippingCheap:   diag.IsSkippingCheap,
					}
					if !diag.ResetAt.IsZero() {
						aj.ResetAt = diag.ResetAt.UTC().Format(time.RFC3339)
					}
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(aj)
				}
				return printAdaptiveState(cmd.OutOrStdout(), diag)
			}

	cmd.Flags().String("model", "", "Requested model route key (e.g. qwen3.5-27b)")
	cmd.Flags().Bool("json", false, "Output JSON")
	cmd.Flags().Bool("adaptive", false, "Show adaptive min-tier state (window, success rate, effective floor)")
	cmd.Flags().Int("adaptive-window", escalation.DefaultAdaptiveMinTierWindow, "Trailing window size for adaptive state display")
	cmd.AddCommand(f.newAgentRouteStatusResetCommand())
	return cmd
}

// printAdaptiveState writes a human-readable adaptive min-tier diagnostic
// block to w. It provides enough information to answer "why is cheap being
// skipped?" without reading source code.
func printAdaptiveState(w interface{ Write([]byte) (int, error) }, diag escalation.AdaptiveMinTierDiagnostics) error {
	type lineWriter struct{ w interface{ Write([]byte) (int, error) } }
	lw := lineWriter{w}
	writeLine := func(format string, args ...any) {
		fmt.Fprintf(lw.w, format+"\n", args...)
	}

	writeLine("Adaptive Min-Tier State")
	writeLine("%s", strings.Repeat("-", 50))

	writeLine("window size:      %d attempts", diag.WindowSize)

	if diag.ResetAt.IsZero() {
		writeLine("reset at:         (none)")
	} else {
		writeLine("reset at:         %s", diag.ResetAt.UTC().Format(time.RFC3339))
	}

	writeLine("total in window:  %d (all tiers)", diag.TotalInWindow)
	writeLine("cheap attempts:   %d (contributing to success rate)", diag.CheapAttempts)
	if diag.CheapInfraSkipped > 0 {
		writeLine("infra-skipped:    %d (excluded: no_viable_provider / harness_not_installed)", diag.CheapInfraSkipped)
	}
	writeLine("cheap successes:  %d", diag.CheapSuccesses)
	writeLine("success rate:     %.2f  (threshold: %.2f, min-samples: %d)",
		diag.CheapSuccessRate, diag.Threshold, diag.MinSamples)

	if diag.IsSkippingCheap {
		writeLine("effective floor:  %s  [cheap tier is SKIPPED — success rate below threshold]",
			string(diag.EffectiveFloor))
		writeLine("")
		writeLine("To reset: ddx agent route-status reset --yes")
	} else {
		writeLine("effective floor:  %s  [cheap tier is eligible]",
			string(diag.EffectiveFloor))
	}
	return nil
}

